def _extract_emotional_markers(text):
    # Simple emotional keyword and sentiment extraction
    emotional_keywords = {
        'positive': ['happy', 'excited', 'joy', 'love', 'great'],
        'negative': ['sad', 'angry', 'frustrated', 'upset', 'hurt'],
        'neutral': ['okay', 'fine', 'neutral']
    }
    
    markers = {
        'keywords': [],
        'sentiment': 'neutral',
        'intensity': 0
    }
    
    text_lower = text.lower()
    
    for category, words in emotional_keywords.items():
        matches = [word for word in words if word in text_lower]
        if matches:
            markers['keywords'].extend(matches)
            markers['sentiment'] = category
            markers['intensity'] = len(matches)
    
    return markers

def _assess_narrative_coherence(markers):
    # Basic coherence scoring
    coherence_factors = {
        'keyword_diversity': len(set(markers['keywords'])) / max(1, len(markers['keywords'])),
        'sentiment_stability': 1 if markers['sentiment'] != 'neutral' else 0.5,
        'emotional_intensity': min(markers['intensity'] / 5, 1)
    }
    
    coherence_score = sum(coherence_factors.values()) / len(coherence_factors)
    return round(coherence_score * 100, 2)

